OnRecvSpinAck_Test( ack, isUnshow = false )
{
    // 處理從伺服器接收到的轉輪結果
    let info = RecoverSpinAck.getInstance().RecoverFromSpinAck( ack );
    error( "SpinAck after:", info );

    this.SpinAck = info;

    this.m_buyBonus?.CleanInfo();
    if (!isUnshow) {
        this.AccumulatedWin = 0;
    }

    // 判斷是否要進入FG
    if (this.SpinAck.RoundQueue.length > 1) {
        if ( !isUnshow || this.CurRoundIndex === 0 ) {
            const firstRoundInfo = this.SpinAck.RoundQueue[0];
            if (firstRoundInfo.NextFeverGameType === FeverGameType.FreeGame) {
                this.IsGoingToFree = true;
            }
        }
    }

    // 地Bar按鈕狀態
    if ( newBottombarManager.IsAutoSpin && !this.m_isHardStop )
    {
        newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP );
    }

    // 設定當局盤面資訊
    this.SetNowRoundInfo( this.SpinAck.RoundQueue[ this.CurRoundIndex ] );



    // 如果開啟快停
    if ( this.m_isHardStop )
    {
        if ( this.IsFreeGame )
        {
            this.m_slotReels.ClickStopBtn();
        }
        else
        {
            if ( !this.m_isMgOmen )
            {
                this.m_slotReels.ClickStopBtn();
            }
        }
        newBottombarManager.SetSpinWithSpeed();
    }
    else
    {
        if ( !newBottombarManager.IsAutoSpin )
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
        }
    }
}

